sql:
SELECT candidate_name
FROM candidates
WHERE date_of_birth = (SELECT MIN(date_of_birth) FROM candidates);

SELECT candidate_id, total_assets
FROM candidate_finances
ORDER BY total_assets DESC;

external_knowledge:
- The 'top three candidates' refers to candidates with the highest number of followers on social media platforms; 
- 'parties' refer to political parties; 
- 'constituencies' refer to the specific geographic areas that candidates are elected to represent; 
- 'average votes' refer to the average number of votes obtained by the party in different constituencies and years; 
- 'total assets' and 'total liabilities' refer to the candidates' financial information.

sql:
SELECT candidate_name
FROM candidates
WHERE year_id = (SELECT year_id FROM election_years WHERE year_name = '2023');

SELECT candidate_name
FROM candidates
WHERE party_id = (SELECT party_id FROM parties WHERE party_name = 'Party Name');
